BEGIN; CREATE TABLE IF NOT EXISTS public.accounting_debt_suppliers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text NULL, name text NOT NULL, default_payment_term_days integer NOT NULL DEFAULT 30 CHECK (default_payment_term_days BETWEEN 0 AND 3650), note text NULL, created_at timestamptz NOT NULL DEFAULT now(), created_by uuid NULL REFERENCES public.profiles(id), updated_at timestamptz NOT NULL DEFAULT now(), updated_by uuid NULL REFERENCES public.profiles(id), deleted_at timestamptz NULL, deleted_by uuid NULL REFERENCES public.profiles(id)); ALTER TABLE public.accounting_debt_invoices ADD COLUMN IF NOT EXISTS supplier_id uuid NULL REFERENCES public.accounting_debt_suppliers(id); CREATE INDEX IF NOT EXISTS idx_acc_debt_suppliers_name_live ON public.accounting_debt_suppliers(name) WHERE deleted_at IS NULL; CREATE UNIQUE INDEX IF NOT EXISTS idx_acc_debt_suppliers_code_live ON public.accounting_debt_suppliers(lower(code)) WHERE deleted_at IS NULL AND code IS NOT NULL; CREATE INDEX IF NOT EXISTS idx_acc_debt_invoices_supplier ON public.accounting_debt_invoices(supplier_id) WHERE deleted_at IS NULL; DROP TRIGGER IF EXISTS trg_acc_debt_suppliers_touch ON public.accounting_debt_suppliers; CREATE TRIGGER trg_acc_debt_suppliers_touch BEFORE INSERT OR UPDATE ON public.accounting_debt_suppliers FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_touch_row(); DROP TRIGGER IF EXISTS trg_acc_debt_suppliers_block_delete ON public.accounting_debt_suppliers; CREATE TRIGGER trg_acc_debt_suppliers_block_delete BEFORE DELETE ON public.accounting_debt_suppliers FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_block_hard_delete(); ALTER TABLE public.accounting_debt_suppliers ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "acc_debt_suppliers_select" ON public.accounting_debt_suppliers; CREATE POLICY "acc_debt_suppliers_select" ON public.accounting_debt_suppliers FOR SELECT TO authenticated USING (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_suppliers_insert" ON public.accounting_debt_suppliers; CREATE POLICY "acc_debt_suppliers_insert" ON public.accounting_debt_suppliers FOR INSERT TO authenticated WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_suppliers_update" ON public.accounting_debt_suppliers; CREATE POLICY "acc_debt_suppliers_update" ON public.accounting_debt_suppliers FOR UPDATE TO authenticated USING (public.can_manage_accounting_debt()) WITH CHECK (public.can_manage_accounting_debt()); GRANT SELECT, INSERT, UPDATE ON public.accounting_debt_suppliers TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
